    let error_of_xml name xml =
      match name with
      | "InternalException" ->
          `InternalException (InternalException.of_xml xml)
      | "InvalidAccessException" ->
          `InvalidAccessException (InvalidAccessException.of_xml xml)
      | "InvalidInputException" ->
          `InvalidInputException (InvalidInputException.of_xml xml)
      | "LimitExceededException" ->
          `LimitExceededException (LimitExceededException.of_xml xml)
      | "ResourceNotFoundException" ->
